from collections import defaultdict, OrderedDict


class LFUCache:
    def __init__(self, capacity):
        self.cap = capacity
        self.vals = {}
        self.counts = {}
        self.buckets = defaultdict(OrderedDict)
        self.minf = 0
    def _bump(self, key):
        c = self.counts[key]
        del self.buckets[c][key]
        if not self.buckets[c]:
            del self.buckets[c]
            if self.minf == c:
                self.minf = c + 1
        self.counts[key] = c + 1
        self.buckets[c + 1][key] = None
    def get(self, key):
        if key not in self.vals:
            return -1
        self._bump(key)
        return self.vals[key]
    def put(self, key, value):
        if self.cap <= 0:
            return
        if key in self.vals:
            self.vals[key] = value
            self._bump(key)
            return
        if len(self.vals) >= self.cap:
            victim, _ = self.buckets[self.minf].popitem(last=False)
            del self.vals[victim]
            del self.counts[victim]
        self.vals[key] = value
        self.counts[key] = 1
        self.buckets[1][key] = None
        self.minf = 1

