class LFUCache {
    constructor(capacity) {
        this.cap = capacity;
        this.vals = new Map();
        this.counts = new Map();
        this.buckets = new Map();
        this.minf = 0;
    }
    _bucket(c) {
        if (!this.buckets.has(c)) this.buckets.set(c, new Map());
        return this.buckets.get(c);
    }
    _bump(key) {
        const c = this.counts.get(key);
        const b = this._bucket(c);
        b.delete(key);
        if (b.size === 0) {
            this.buckets.delete(c);
            if (this.minf === c) this.minf = c + 1;
        }
        this.counts.set(key, c + 1);
        this._bucket(c + 1).set(key, true);
    }
    get(key) {
        if (!this.vals.has(key)) return -1;
        this._bump(key);
        return this.vals.get(key);
    }
    put(key, value) {
        if (this.cap <= 0) return;
        if (this.vals.has(key)) {
            this.vals.set(key, value);
            this._bump(key);
            return;
        }
        if (this.vals.size >= this.cap) {
            const b = this._bucket(this.minf);
            const victim = b.keys().next().value;
            b.delete(victim);
            this.vals.delete(victim);
            this.counts.delete(victim);
        }
        this.vals.set(key, value);
        this.counts.set(key, 1);
        this._bucket(1).set(key, true);
        this.minf = 1;
    }
}
